void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

ret = mix(GetBlur2(vUv),GetPixel(vUv),0.4);

ret = (ret.y-ret.x*0.5)*mix(vec3(2.1,1.4,0.1),1,ret.x)*2.4;
//MilkDrop3 Color Mode:
ret /= vec3(0.6,1.2,-1.1);

  fragColor = ret;
}
